<?php
namespace Tests\Feature;
use App\Actions\{CreateInventoryAdjustmentAction,CreateMaterialPurchaseAction,CreateMaterialWriteOffAction};use App\Models\{Material,Project,Unit,User};use App\Services\InventoryService;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class InventoryTest extends TestCase{use RefreshDatabase; private function fixture(): array{$user=User::factory()->create();$project=Project::create(['user_id'=>$user->id,'name'=>'Дом']);$unit=Unit::create(['name'=>'штука','short_name'=>'шт']);$material=Material::create(['project_id'=>$project->id,'unit_id'=>$unit->id,'name'=>'Кирпич']);return [$project,$material];}
public function test_purchase_increases_stock(): void{[$p,$m]=$this->fixture();app(CreateMaterialPurchaseAction::class)->execute(['project_id'=>$p->id,'date'=>'2026-05-10','payment_status'=>'paid','items'=>[['material_id'=>$m->id,'quantity'=>10,'unit_price'=>100]]]);$this->assertSame(10.0,app(InventoryService::class)->getCurrentStock($p,$m));}
public function test_write_off_decreases_stock_and_prevents_negative(): void{[$p,$m]=$this->fixture();app(CreateMaterialPurchaseAction::class)->execute(['project_id'=>$p->id,'date'=>'2026-05-10','payment_status'=>'paid','items'=>[['material_id'=>$m->id,'quantity'=>10,'unit_price'=>100]]]);app(CreateMaterialWriteOffAction::class)->execute(['project_id'=>$p->id,'material_id'=>$m->id,'date'=>'2026-05-11','quantity'=>4]);$this->assertSame(6.0,app(InventoryService::class)->getCurrentStock($p,$m));$this->expectException(\RuntimeException::class);app(CreateMaterialWriteOffAction::class)->execute(['project_id'=>$p->id,'material_id'=>$m->id,'date'=>'2026-05-12','quantity'=>7]);}
public function test_adjustments_and_average_cost(): void{[$p,$m]=$this->fixture();app(CreateMaterialPurchaseAction::class)->execute(['project_id'=>$p->id,'date'=>'2026-05-10','payment_status'=>'paid','items'=>[['material_id'=>$m->id,'quantity'=>10,'unit_price'=>100],['material_id'=>$m->id,'quantity'=>10,'unit_price'=>200]]]);app(CreateInventoryAdjustmentAction::class)->execute(['project_id'=>$p->id,'material_id'=>$m->id,'date'=>'2026-05-11','type'=>'adjustment','quantity'=>5]);app(CreateInventoryAdjustmentAction::class)->execute(['project_id'=>$p->id,'material_id'=>$m->id,'date'=>'2026-05-12','type'=>'adjustment','quantity'=>-3]);$this->assertSame(22.0,app(InventoryService::class)->getCurrentStock($p,$m));$this->assertSame(150.0,app(InventoryService::class)->getAverageUnitCost($p,$m));}}
